
// my  ##sort     сортировать нечёт-чёт и меньш-больш   способ1 некрасивый  разделение на 2 массива
function evenOddValSort (masiv) {
  var masivEven =[], masivOdd=[];
  for(var i = 0; i < masiv.length; i++){
	if(masiv[i]%2===1) masivEven.push(masiv[i]);	
	else masivOdd.push(masiv[i]);  
  }
  function compareNumbers( value1 , value2 ) { return value1 - value2 ; } 
  masivEven = masivEven.sort(compareNumbers); 
  masivOdd = masivOdd.sort(compareNumbers); 
  return (masiv =  masivEven.concat(masivOdd));
}
var numbersArray = [601, 520, 625, 58, 5, 54, 3, 2, 1, 66, 33, 2, 9, 55, 9];
assert(1, evenOddValSort(numbersArray));   //1//////////////////////




