//  Подмассив наибольшей суммы    концептТакое решение имеет оценку сложности O(n^2) !!
//  (при увеличении массива в 2 раза алгоритм требует в 4 раза больше времени. 

function getMaxSubSum(arr) {
var maxSum = 0; // если совсем не брать элементов, то сумма 0
for (var i = 0; i < arr.length; i++) {
var sumFixedStart = 0;
for (var j = i; j < arr.length; j++) {
sumFixedStart += arr[j];
maxSum = Math.max(maxSum, sumFixedStart);
}
}
return maxSum;
}
