//  ##пример     изменение св-ва объекта  (добавление класса)
var obj = {
className: 'open menu'
}

function addClass(obj, cls) {
  var classes = obj.className ? obj.className.split(' ') : [];//если св-ва нет - сделать
  for (var i=0; i<classes.length; i++) {
	if(classes[i] === cls) return;     // проверка если уже есть - не добавлять
  }
  classes.push(cls); // добавить
  obj.className = classes.join(' '); // и обновить свойство
}

addClass(obj, 'me');
assert(1, obj.className);   //19/////////////////







