// концепт MY    !!  + см палиндром    Отфильтровать анаграммы см концепт1+
//  здесь my это 1 массив с разделителем |||  регистр - разные слова   --
//  в концепт1+   result массив из отдельных массивов    ++
var arr = ["воз", "киборг", "корсет", "Киборг", "ЗОВ", "гробик", "костер", "сектор"];
  var my =[];                    //\\\\
  
function acleanMy(arr) {
  for (var i=0; i<arr.length; i++) { 
	my.push('|||');  my.push(arr[i]);    //\\\\\
	for (var j=i+1; j<arr.length; j++) {
	  if(arr[i].length !== arr[j].length)  continue;
	  var tempI = arr[i].toLowerCase().split('').sort().join();
	  var tempJ = arr[j].toLowerCase().split('').sort().join();
	  if(tempI === tempJ){ 
		if(arr[i]!== arr[j]) my.push(arr[j]);    //\\\\\
		arr.splice(j, 1); 
		j--;
	  }
	}
  }
  return arr;
}

assert(1, acleanMy(arr)+' --- '+my.join(" "));   //22//////////////// 


//  концепт1     Отфильтровать анаграммы
function aclean(arr) {
  var obj = {};  // этот объект будем использовать для уникальности
  var result = [];
  for (var i = 0; i < arr.length; i++) {
	// разбить строку на буквы, отсортировать и слить обратно
	var sorted = arr[i].toLowerCase().split('').sort().join('');
	obj[sorted] = arr[i]; // сохраняет только одно значение с таким ключом  ##приём
  }
  // теперь в obj находится для каждого ключа ровно одно значение
  for (var key in obj) result.push(obj[key]);
  return result;
}
var arr = ["воз", "киборг", "корсет", "ЗОВ", "гробик", "костер", "сектор"];
assert(1, aclean(arr));   //23/////////////////



//  концепт1+ MY   !!!     Отфильтровать анаграммы     
function acleanMyMy(arr) {
  arrClon = arr.slice();  //!! клонировал, чтобы не исказить первонач массив
  var obj = {};   // этот объект будем использовать для уникальности
  for (var i = 0; i < arrClon.length; i++) {
	arrClon[i] = arrClon[i].toLowerCase();
	var sorted = arrClon[i].split('').sort().join('');
	if(!obj[sorted]) obj[sorted]=[];  
	if(!~obj[sorted].indexOf(arrClon[i])) obj[sorted].push(arrClon[i]); 
  }
  var result = [], resultBig = [];
  for (var key in obj) {
	result.push(obj[key]);  // все
	for (var i=0; i<5 ; i++) {  // ??  возможно ли больше 5 анаграмм?
	  if(obj[key].length===i+2) {// массив групп анаграмм >1, 2, ...
		if(!resultBig[i]) resultBig[i] = [i+2] ; // индикатор в начале группы. убрать?
		resultBig[i].push(obj[key]); 
	  }
	}
  }
  return resultBig; //\\\\\\\  вариант  result. // массив групп анаграмм >1, 2 ...
}

