// Оставить уникальные элементы массива

function unique(arr) {
  var obj = {};  // этот объект будем использовать для  см уникальности
  for (var i = 0; i < arr.length; i++) {
	var sorted = arr[i];
	obj[sorted] = true; 
  }
  return Object.keys(obj)
}

