arr = [1,2,3,4,5];

// концепт  my  ##reduce   Массив частичных сумм. мой вариант лучше? их - чуть быстрее
function getSums(arr) {
  result = arr.slice();
  
  var totalSum = result.reduce(function (sum, item, index) { 
	result[index] = item+sum;
	return item+sum;
  });
  return result;
}
