// концепт1   ##reduce     Массив частичных сумм
function getSums1(arr) {
  var result = [];
  var totalSum = arr.reduce(function(sum, item) {
	result.push(sum);
	return sum + item;
  });
  result.push(totalSum);
  return result;
}
