// концепт2 my2  традицион методами      Массив частичных сумм
function getSums2(arr) {
  var result = [], sum = 0;
  for (var i=0; i<arr.length; i++) {
	 sum += arr[i];
	 result[i] = sum;
  }
  return result;
}

